DELETE FROM TB_RPLIKE
 WHERE USER_NUMB = #{userNumb}
   AND REPORT_NUMB = #{reportNumb}

mapper.insert:

    SELECT TM_BOOK_REPORT_SEQ.NEXTVAL FROM DUAL

/* setReport */
INSERT INTO TM_BOOK_REPORT(
            REPORT_NUMB
          , USER_NUMB
          , BOOK_NUMB
          , REPORT_STAT
          , REPORT_STDT
          , REPORT_ENDT
          , REPORT_GRDE
          , REPORT_COLR
          , PUBC_YSNO
          , REPORT_CNTN
) VALUES (  #{reportNumb}
          , #{userNumb}
          , #{bookNumb}
          , #{reportStat}
          , #{reportStdt}
          , #{reportEndt}
          , #{reportGrde}
          , #{reportColr}
          , #{pubcYsno}
          , #{reportCntn}
)

mapper.update:
/* uptReport */
UPDATE TM_BOOK_REPORT
   SET REPORT_STAT = #{reportStat}
     , REPORT_STDT = #{reportStdt}
     , REPORT_ENDT = #{reportEndt}
     , REPORT_GRDE = #{reportGrde}
     , REPORT_COLR = #{reportColr}
     , PUBC_YSNO = #{pubcYsno}
     , REPORT_CNTN = #{reportCntn}
 WHERE REPORT_NUMB = #{reportNumb}
   AND USER_NUMB = #{userNumb}

/* uptReportStatusGrade */
UPDATE TM_BOOK_REPORT

       REPORT_STAT = #{reportStat}
     , REPORT_GRDE = #{reportGrde}

     , REPORT_ENDT = #{reportEndt}


 WHERE REPORT_NUMB = #{reportNumb}
   AND USER_NUMB = #{userNumb}

mapper.delete:
/* delReport */
DELETE FROM TM_BOOK_REPORT
 WHERE REPORT_NUMB = #{reportNumb}
   AND USER_NUMB = #{userNumb}
